import { extname } from 'node:path';

export type CaptureIqFormat = 'rtl_u8' | 'signed_iq8';

/**
 * Handles the gnosis infer Capture Iq Format From Path workflow.
 */
export function inferCaptureIqFormatFromPath(path: string): CaptureIqFormat {
  const ext = extname(path).toLowerCase();
  if (ext === '.cs8' || ext === '.s8') {
    return 'signed_iq8';
  }
  return 'rtl_u8';
}

/**
 * Normalizes capture bytes to rtl_sdr-style offset u8 IQ (I,Q interleaved).
 * - `rtl_u8`: already [0..255] centered at 128.
 * - `signed_iq8`: two's-complement int8 bytes converted with xor 0x80.
 */
export function normalizeCaptureToRtlU8(
  raw: Uint8Array,
  format: CaptureIqFormat,
): Uint8Array {
  if (raw.length % 2 !== 0) {
    throw new Error('normalizeCaptureToRtlU8: IQ byte length must be even');
  }
  if (format === 'rtl_u8') {
    return raw;
  }
  const out = new Uint8Array(raw.length);
  for (let i = 0; i < raw.length; i++) {
    out[i] = raw[i]! ^ 0x80;
  }
  return out;
}
